    "STATEFUL_PRIMITIVES": {
        "fqn": "STATEFUL_PRIMITIVES",
        "kind": "property",
        "title": "STATEFUL_PRIMITIVES",
        "summary": "Frozen set of every fully-qualified call name the compiler tracks for\nstatic-analysis (`stateful-call-inside-loop`) and slot-id injection\n. Each entry carries a `slot` flag: `slot: true`\nprimitives allocate per-callsite hidden state and get a string-literal\nslot id injected as their first argument; `slot: false` primitives are\npure helpers that ride along in the set because Pine still forbids\nthem inside loops (e.g. `ta.nz`).",
        "examples": [
            "import { STATEFUL_PRIMITIVES } from \"@invinite-org/chartlang-core\";\nfor (const entry of STATEFUL_PRIMITIVES) {\nif (entry.name === \"ta.ema\" && entry.slot) {\n// compiler injects an id here\n}\n}"
        ],
        "since": "0.1",
        "stability": "stable"
    },
    "STATEFUL_PRIMITIVES_BY_NAME": {
        "fqn": "STATEFUL_PRIMITIVES_BY_NAME",
        "kind": "property",
        "title": "STATEFUL_PRIMITIVES_BY_NAME",
        "summary": "/**\nName → entry index of  {@link STATEFUL_PRIMITIVES} . The compiler's\n`callsiteIdInjection` and `statefulCallInLoop` passes consult this map\nby callee name once per call site — O(1) lookup instead of an O(n) scan\nover the 179-entry set on every visited call. The map is derived from\nthe same canonical entry list as  {@link STATEFUL_PRIMITIVES} so adding\na primitive to the set adds it here automatically.",
        "examples": [
            "import { STATEFUL_PRIMITIVES_BY_NAME } from \"@invinite-org/chartlang-core\";\nconst entry = STATEFUL_PRIMITIVES_BY_NAME.get(\"ta.ema\");\n// entry is { name: \"ta.ema\", slot: true } | undefined"
        ],
        "since": "0.2",
        "stability": "stable"
    },
    "StatefulPrimitiveEntry": {
        "fqn": "StatefulPrimitiveEntry",
        "kind": "type",
        "title": "StatefulPrimitiveEntry",
        "summary": "/**\nPer-entry shape of  {@link STATEFUL_PRIMITIVES} . `name` is the\nfully-qualified call (`ta.ema`, `plot`, `hline`, `alert`); `slot`\nis `true` for every primitive whose call site needs a compiler-\ninjected slot id, `false` for the stateless helpers that ride along\nin the set for in-loop diagnostics (currently only `ta.nz`).",
        "examples": [
            "const entry: StatefulPrimitiveEntry = { name: \"ta.nz\", slot: false };"
        ],
        "since": "0.1",
        "stability": "stable"
    },
