    "StringSeriesSlot": {
        "fqn": "StringSeriesSlot",
        "kind": "type",
        "title": "StringSeriesSlot",
        "summary": "/**\nThe string counterpart of  {@link NumberSeriesSlot} — a user-allocated,\nwritable, indexable **string** history, the value half of  {@link state} 's\n`stringSeries` slot. Both a writable scalar slot (`s.value = label`, like\n`state.string`) **and** an indexable `Series<string>` (`s[1]` reads one bar\nago, `s.current` the current bar). Assign the current bar's value with\n`s.value = …` each step; read history with `s[n]`. Out-of-range / first-bar\nhistory reads are the empty string **`\"\"`**. The runtime backs it with a\nring-buffer view sized to the script's max lookback.",
        "examples": [
            "function priorLabel(s: StringSeriesSlot, label: string): string {\ns.value = label;\nreturn s[1]; // \"\" on the first bar\n}"
        ],
        "since": "1.5",
        "stability": "stable"
    },
    "sum": {
        "fqn": "sum",
        "kind": "property",
        "title": "sum",
        "summary": "Variadic skip-NaN scalar sum — adds only the finite arguments and returns\nNaN for an empty or all-non-finite list. A fixed-arity scalar reducer,\ndistinct from the rolling `ta.*` / `state.array(...).sum()` forms. Each\nargument is coerced with `Number(...)` first, so a number-coercible series\nview (e.g. a `bar.*` field) reduces by its current value instead of being\nsilently skipped as a non-number object.",
        "examples": [
            "math.sum(2, Number.NaN, 4); // 6"
        ],
        "since": "1.4",
        "stability": "stable"
    },
    "SupertrendOpts": {
        "fqn": "SupertrendOpts",
        "kind": "type",
        "title": "SupertrendOpts",
        "summary": "Options bag for `ta.supertrend`. `length` is the ATR period\n(default `10`); `multiplier` scales the band offset from `hl2`\n(default `3`). `offset` shifts the read window backwards\n(accepted on the surface). The source is hard-coded\nto `hl2` (Pine-canonical Supertrend); a `source` opt could land in\na follow-up.",
        "examples": [
            "const opts: SupertrendOpts = { length: 10, multiplier: 3 };"
        ],
        "since": "0.2",
        "stability": "stable"
    },
    "SupertrendResult": {
        "fqn": "SupertrendResult",
        "kind": "type",
        "title": "SupertrendResult",
        "summary": "The two-series result of `ta.supertrend` — the trailing-stop\n`line` (the active final band per current direction) and the\nper-bar `direction` (`+1` uptrend → `line = finalLower`,\n`-1` downtrend → `line = finalUpper`, NaN during warmup).",
        "examples": [
            "const s = ta.supertrend({ length: 10, multiplier: 3 });\nplot(s.line);"
        ],
        "since": "0.2",
        "stability": "stable"
    },
